import sys
from typing import List
import heapq

class Twitter:
    def __init__(self):
        self.tweets = {}
        self.follows = {}
        self.time = 0

    def postTweet(self, userId: int, tweetId: int) -> None:
        self.time += 1
        if userId not in self.tweets:
            self.tweets[userId] = []
        heapq.heappush(self.tweets[userId], (-self.time, tweetId))

    def getNewsFeed(self, userId: int) -> List[int]:
        feed = []
        if userId in self.tweets:
            feed.extend(self.tweets[userId])
        if userId in self.follows:
            for followeeId in self.follows[userId]:
                if followeeId in self.tweets:
                    feed.extend(self.tweets[followeeId])
        heapq.heapify(feed)
        result = []
        while feed and len(result) < 10:
            _, tweetId = heapq.heappop(feed)
            result.append(tweetId)
        return result

    def follow(self, followerId: int, followeeId: int) -> None:
        if followerId not in self.follows:
            self.follows[followerId] = set()
        self.follows[followerId].add(followeeId)

    def unfollow(self, followerId: int, followeeId: int) -> None:
        if followerId in self.follows and followeeId in self.follows[followerId]:
            self.follows[followerId].remove(followeeId)

if __name__ == '__main__':
    Q = int(sys.stdin.readline().strip())
    twitter = Twitter()
    for _ in range(Q):
        query = list(map(int, sys.stdin.readline().strip().split()))
        if query[0] == 1:
            twitter.postTweet(query[1], query[2])
        elif query[0] == 2:
            feed = twitter.getNewsFeed(query[1])
            print(len(feed))
            print(' '.join(map(str, feed)))
        elif query[0] == 3:
            twitter.follow(query[1], query[2])
        elif query[0] == 4:
            twitter.unfollow(query[1], query[2])

