#include <numeric>
#include <iostream>
#include <vector>
#include <queue>
#include <unordered_map>
#include <unordered_set>

using namespace std;

class Twitter {
public:
    Twitter() : time(0) {}

    void postTweet(int userId, int tweetId) {
        time++;
        tweets[userId].emplace(-time, tweetId);
    }

    vector<int> getNewsFeed(int userId) {
        vector<int> feed;
        if (tweets.count(userId)) {
            feed = getVector(tweets[userId]);
        }
        if (follows.count(userId)) {
            for (int followeeId : follows[userId]) {
                if (tweets.count(followeeId)) {
                    auto vec = getVector(tweets[followeeId]);
                    feed.insert(feed.end(), vec.begin(), vec.end());
                }
            }
        }
        make_heap(feed.begin(), feed.end());
        vector<int> result;
        for (int i = 0; i < 10 && !feed.empty(); i++) {
            result.push_back(feed[0]);
            pop_heap(feed.begin(), feed.end());
            feed.pop_back();
        }
        return result;
    }

    void follow(int followerId, int followeeId) {
        follows[followerId].insert(followeeId);
    }

    void unfollow(int followerId, int followeeId) {
        if (follows.count(followerId) && follows[followerId].count(followeeId)) {
            follows[followerId].erase(followeeId);
        }
    }

private:
    int time;
    unordered_map<int, priority_queue<pair<int, int>>> tweets;
    unordered_map<int, unordered_set<int>> follows;

    vector<int> getVector(priority_queue<pair<int, int>> pq) {
        vector<int> vec;
        priority_queue<pair<int, int>> temp = pq;
        while (!temp.empty()) {
            vec.push_back(temp.top().second);
            temp.pop();
        }
        return vec;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int Q;
    cin >> Q;
    Twitter twitter;
    for (int _ = 0; _ < Q; _++) {
        int query[3];
        cin >> query[0];
        if (query[0] == 1) {
            cin >> query[1] >> query[2];
            twitter.postTweet(query[1], query[2]);
        } else if (query[0] == 2) {
            cin >> query[1];
            vector<int> feed = twitter.getNewsFeed(query[1]);
            cout << feed.size() << '\n';
            for (int tweetId : feed) {
                cout << tweetId << ' ';
            }
            cout << '\n';
        } else if (query[0] == 3) {
            cin >> query[1] >> query[2];
            twitter.follow(query[1], query[2]);
        } else if (query[0] == 4) {
            cin >> query[1] >> query[2];
            twitter.unfollow(query[1], query[2]);
        }
    }
    return 0;
}
